import React from 'react';
import { View, StyleSheet } from 'react-native';

export interface CheckboxIndicatorProps {
  checked: boolean;
  disabled?: boolean;
  invalid?: boolean;
  size?: 'sm' | 'md' | 'lg';

  borderColor?: string;
  checkedBorderColor?: string;
  checkedBackgroundColor?: string;
  checkmarkColor?: string;
  invalidBorderColor?: string;
  backgroundColor?: string;
}

const SIZES = { sm: 18, md: 22, lg: 28 };
const BORDER_RADII = { sm: 3, md: 4, lg: 5 };

export default function CheckboxIndicator({
                                            checked,
                                            disabled,
                                            invalid,
                                            size = 'md',

                                            borderColor = '#d1d5db',
                                            checkedBorderColor = '#6366f1',
                                            checkedBackgroundColor = '#6366f1',
                                            checkmarkColor = '#ffffff',
                                            invalidBorderColor = '#ef4444',
                                            backgroundColor = '#ffffff',
                                          }: CheckboxIndicatorProps) {
  const s = SIZES[size];
  const r = BORDER_RADII[size];
  const checkSize = s * 0.5;

  const finalBorderColor = invalid
    ? invalidBorderColor
    : checked
      ? checkedBorderColor
      : borderColor;

  const finalBackgroundColor = checked ? checkedBackgroundColor : backgroundColor;

  return (
    <View
      style={[
        styles.box,
        {
          width: s,
          height: s,
          borderRadius: r,
          borderColor: finalBorderColor,
          backgroundColor: finalBackgroundColor,
          opacity: disabled ? 0.5 : 1,
        },
      ]}
    >
      {checked && (
        <View
          style={[
            styles.checkmark,
            {
              width: checkSize,
              height: checkSize * 0.6,
              borderColor: checkmarkColor,
            },
          ]}
        />
      )}
    </View>
  );
}

const styles = StyleSheet.create({
  box: {
    borderWidth: 2,
    justifyContent: 'center',
    alignItems: 'center',
  },
  checkmark: {
    borderLeftWidth: 2,
    borderBottomWidth: 2,
    transform: [{ rotate: '-45deg' }, { translateY: -1 }],
  },
});
